34	function checkTmuxSession(sessionName) {
35	  try {
36	    execSync(`tmux has-session -t ${sessionName} 2>/dev/null`, { encoding: 'utf8' });
37	    return true;
38	  } catch {
39	    return false;
40	  }
41	}
42	
43	function checkPidAlive(pid) {
44	  try {
45	    process.kill(pid, 0);
46	    return true;
47	  } catch {
48	    return false;
49	  }
50	}
