113	// Get all team info
114	function getTeams() {
115	  const teams = [];
116	  if (!fs.existsSync(TEAMS_DIR)) return teams;
117	
118	  const teamDirs = fs.readdirSync(TEAMS_DIR);
119	
120	  for (const teamName of teamDirs) {
121	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
122	    try {
123	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
124	      const taskListPath = path.join(CLAUDE_DIR, 'tasks', teamName);
125	
126	      let taskStatus = { total: 0, completed: 0, inProgress: 0, pending: 0 };
127	      if (fs.existsSync(taskListPath)) {
128	        const taskFiles = fs.readdirSync(taskListPath).filter(f => f.endsWith('.json'));
129	        for (const taskFile of taskFiles) {
130	          try {
131	            const task = JSON.parse(fs.readFileSync(path.join(taskListPath, taskFile), 'utf8'));
132	            taskStatus.total++;
133	            if (task.status === 'completed') taskStatus.completed++;
134	            else if (task.status === 'in_progress') taskStatus.inProgress++;
135	            else if (task.status === 'pending') taskStatus.pending++;
136	          } catch {}
137	        }
138	      }
139	
140	      teams.push({
141	        name: teamName,
142	        description: config.description || '',
143	        memberCount: config.members?.length || 0,
144	        taskStatus
145	      });
146	    } catch {}
147	  }
148	
149	  return teams;
150	}
