173	function spawnBackgroundProcess(name, cmd) {
174	  const env = buildEnvScript();
175	  const logFile = path.join(__dirname, `logs/${name}-${Date.now()}.log`);
176	  const logsDir = path.join(__dirname, 'logs');
177	  if (!fs.existsSync(logsDir)) fs.mkdirSync(logsDir, { recursive: true });
178	
179	  // Build a bash inline script with env vars, run in background via nohup
180	  const escapedCmd = cmd.replace(/'/g, "'\\''");
181	  const bgCmd = `CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS='${env.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS}' ` +
182	    `ANTHROPIC_BASE_URL='${env.ANTHROPIC_BASE_URL}' ` +
183	    `ANTHROPIC_AUTH_TOKEN='${env.ANTHROPIC_AUTH_TOKEN}' ` +
184	    `ANTHROPIC_API_KEY='${env.ANTHROPIC_API_KEY}' ` +
185	    `ANTHROPIC_MODEL='${env.ANTHROPIC_MODEL}' ` +
186	    `nohup ${env.CLAUDE_BIN} ${escapedCmd} > '${logFile}' 2>&1 & echo $!`;
187	
188	  return { bgCmd, logFile };
189	}
