277	// API: Spawn agent - runs the claude command in the Mac background (no visible window)
278	app.post('/api/spawn', async (req, res) => {
279	  try {
280	    const { name, role, prompt, description } = req.body;
281	    const fullPrompt = prompt || `${name} is a ${role} agent.`;
282	
283	    // Build the claude command
284	    let cmd;
285	    if (name.toLowerCase() === 'trevor' || role === 'manager' || role === 'trevor') {
286	      cmd = `--agent=trevor "${fullPrompt.replace(/"/g, '\\"')}"`;
287	    } else {
288	      cmd = `"${fullPrompt.replace(/"/g, '\\"')}"`;
289	    }
290	
291	    const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
292	    const teamName = `agent-${safeName}-${Date.now()}`;
293	    const backgroundId = `spawn-${safeName}-${Date.now()}`;
294	
295	    const { bgCmd: fullBgCmd, logFile } = spawnBackgroundProcess(backgroundId, cmd);
296	
297	    exec(fullBgCmd, (err, stdout) => {
298	      if (err) console.error('Spawn error:', err.message);
299	      else if (stdout) {
300	        const pid = parseInt(stdout.trim(), 10);
301	        if (pid) savePid(`${teamName}.pid`, pid);
302	        console.log(`Spawned agent: ${name} (PID: ${pid})`);
303	      }
304	    });
305	
306	    // Save description
307	    if (description) {
308	      const descriptions = loadDescriptions();
309	      descriptions[name] = description;
310	      saveDescriptions(descriptions);
311	    }
312	
313	    // Create team entry so the dashboard can discover this agent
314	    const teamDir = path.join(TEAMS_DIR, teamName);
315	    const taskListDir = path.join(CLAUDE_DIR, 'tasks', teamName);
316	
317	    fs.mkdirSync(teamDir, { recursive: true });
318	    fs.mkdirSync(taskListDir, { recursive: true });
319	
320	    const teamConfig = {
321	      description: description || `${name} — ${role} agent`,
322	      leaderSessionId: null,
323	      createdAt: Date.now(),
324	      backgroundId,
325	      members: [{
326	        agentId: `agent-${safeName}`,
327	        name,
328	        agentType: role || 'general-purpose',
329	        backgroundId
330	      }]
331	    };
332	    fs.writeFileSync(
333	      path.join(teamDir, 'config.json'),
334	      JSON.stringify(teamConfig, null, 2)
335	    );
336	
337	    res.json({
338	      success: true,
339	      message: `Agent "${name}" spawned in background (no visible window)`,
340	      name,
341	      teamName,
342	      logFile
343	    });
344	  } catch (err) {
345	    res.status(500).json({ success: false, error: err.message });
346	  }
347	});
