41	// Input
42	const keys = {};
43	let keysDownCount = 0;
44	document.addEventListener('keydown', (e) => {
45	  // Don't capture wasd/arrow keys if user is typing in an input
46	  if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.tagName === 'SELECT') return;
47	  if (['w','a','s','d','ArrowUp','ArrowDown','ArrowLeft','ArrowRight',' '].includes(e.key.toLowerCase())) {
