58	// Office map layout (1 = wall, 0 = floor, 2 = desk, 3 = resting room, 4 = tennis, 5 = basketball, 6 = door, 7 = plant, 8 = lounge chair)
59	// The office is a grid. Agents are placed on desk tiles.
60	function getMap() {
61	  const map = [];
62	  for (let y = 0; y < ROWS; y++) {
63	    const row = [];
64	    for (let x = 0; x < COLS; x++) {
65	      // Outer walls
66	      if (y === 0 || y === ROWS - 1 || x === 0 || x === COLS - 1) {
67	        row.push(1);
68	      } else {
69	        row.push(0);
70	      }
71	    }
72	    map.push(row);
73	  }
74	
75	  // --- Main Office Area (top-center) ---
76	  // Desks in a row
77	  for (let i = 0; i < 4; i++) {
78	    map[3][5 + i * 3] = 2; // Desk
79	    map[3][6 + i * 3] = 2; // Chair
80	  }
81	  for (let i = 0; i < 4; i++) {
82	    map[7][5 + i * 3] = 2;
83	    map[7][6 + i * 3] = 2;
84	  }
85	
86	  // --- Resting Rooms (right side) ---
87	  // Walls of resting rooms
88	  for (let y = 2; y <= 10; y++) {
89	    map[y][28] = 1;
90	    map[y][35] = 1;
91	  }
92	  map[2][28] = 1; map[2][35] = 1;
93	  map[10][28] = 1; map[10][35] = 1;
94	  // Door gap
95	  map[6][35] = 6;
96	  map[10][28] = 6; map[10][29] = 6; map[10][30] = 6; map[10][31] = 6;
97	
98	  // Lounge chairs inside resting room
99	  map[4][30] = 8;
100	  map[4][32] = 8;
101	  map[4][34] = 8;
102	  map[7][30] = 8;
103	  map[7][32] = 8;
104	  map[7][34] = 8;
105	
106	  // --- Sports Area (bottom-center) ---
107	  // Tennis court
108	  for (let y = 15; y <= 23; y++) {
109	    map[y][5] = 1;
110	    map[y][14] = 1;
111	  }
112	  map[15][5] = 1; map[15][14] = 1;
113	  map[23][5] = 1; map[23][14] = 1;
114	  map[15][7] = 6; map[15][8] = 6; // Door
115	  map[15][11] = 6; map[15][12] = 6;
116	
117	  // Basketball court
118	  for (let y = 15; y <= 23; y++) {
119	    map[y][19] = 1;
120	    map[y][28] = 1;
121	  }
122	  map[15][19] = 1; map[15][28] = 1;
123	  map[23][19] = 1; map[23][28] = 1;
124	  map[15][21] = 6; map[15][22] = 6;
125	  map[15][25] = 6; map[15][26] = 6;
126	
127	  // Plants (decorations)
128	  map[2][2] = 7; map[2][10] = 7;
129	  map[2][20] = 7; map[2][26] = 7;
