139	// Check collision
140	function isWalkable(x, y) {
141	  const tile = getTileAt(x, y);
142	  if (tile === 1 || tile === 2 || tile === 8) return false; // wall, desk, chair
143	  if (tile === undefined) return false;
144	  return true;
145	}
146	
147	function getTileAt(x, y) {
148	  if (y < 0 || y >= ROWS || x < 0 || x >= COLS) return 99;
149	  return officeMap[y][x];
150	}
151	
152	// Agent sprites on the map (placed on desk tiles)
153	function getAgentPositions() {
154	  const positions = [];
155	  // Fixed desk positions matching the map
156	  const desks = [
157	    { x: 5, y: 3 }, { x: 8, y: 3 }, { x: 11, y: 3 }, { x: 14, y: 3 },
158	    { x: 5, y: 7 }, { x: 8, y: 7 }, { x: 11, y: 7 }, { x: 14, y: 7 }
159	  ];
160	
161	  agents.forEach((agent, i) => {
162	    if (i < desks.length) {
163	      positions.push({ ...desks[i], agent });
164	    }
165	  });
166	
167	  return positions;
168	}
