170	// Drawing
171	function drawTile(x, y, tile) {
172	  const screenX = x * TILE - camX;
173	  const screenY = y * TILE - camY;
174	
175	  // Skip if off screen
176	  if (screenX < -TILE || screenX > canvas.width + TILE || screenY < -TILE || screenY > canvas.height + TILE) return;
177	
178	  switch (tile) {
179	    case 0: {
180	      // Floor - checkered pattern
181	      ctx.fillStyle = (x + y) % 2 === 0 ? '#f5f0e0' : '#ede8d4';
182	      ctx.fillRect(screenX, screenY, TILE, TILE);
183	      // Subtle grid lines
184	      ctx.strokeStyle = 'rgba(0,0,0,0.05)';
185	      ctx.strokeRect(screenX, screenY, TILE, TILE);
186	      break;
187	    }
188	    case 1: {
189	      // Wall - pixel brick pattern
190	      ctx.fillStyle = '#2a2a4e';
191	      ctx.fillRect(screenX, screenY, TILE, TILE);
192	      // Brick highlights
193	      ctx.fillStyle = '#3a3a6e';
194	      ctx.fillRect(screenX + 2, screenY + 2, TILE - 4, TILE / 2 - 3);
195	      ctx.fillRect(screenX + TILE / 2 + 2, screenY + TILE / 2, TILE / 2 - 4, TILE / 2 - 3);
196	      ctx.fillRect(screenX + 2, screenY + TILE / 2, TILE / 2 - 4, TILE / 2 - 3);
197	      // Edge highlight
198	      ctx.fillStyle = '#4a4a8e';
199	      ctx.fillRect(screenX, screenY, TILE, 3);
200	      ctx.fillRect(screenX, screenY, 3, TILE);
201	      break;
202	    }
203	    case 2: {
204	      // Desk - wood color
205	      ctx.fillStyle = '#8b6914';
206	      ctx.fillRect(screenX + 4, screenY + 8, TILE - 8, TILE - 16);
207	      // Desk top highlight
208	      ctx.fillStyle = '#a68527';
209	      ctx.fillRect(screenX + 6, screenY + 10, TILE - 12, TILE - 22);
210	      break;
211	    }
