427	  const eyeOffY = player.dir === 'up' ? -4 : player.dir === 'down' ? 2 : 0;
428	  if (player.dir !== 'up') {
429	    ctx.fillRect(screenX + 19 + eyeOffX, screenY + 8 + bob + eyeOffY, 3, 3);
430	    ctx.fillRect(screenX + 26 + eyeOffX, screenY + 8 + bob + eyeOffY, 3, 3);
