451	// Main render loop
452	function render() {
453	  // Update player movement
454	  let dx = 0, dy = 0;
455	  const spd = player.speed;
456	  player.moving = false;
457	
458	  if (keys['w'] || keys['arrowup']) { dy = -spd; player.dir = 'up'; player.moving = true; }
459	  else if (keys['s'] || keys['arrowdown']) { dy = spd; player.dir = 'down'; player.moving = true; }
460	  else if (keys['a'] || keys['arrowleft']) { dx = -spd; player.dir = 'left'; player.moving = true; }
461	  else if (keys['d'] || keys['arrowright']) { dx = spd; player.dir = 'right'; player.moving = true; }
462	
463	  if (player.moving) {
464	    player.pixelBob += 0.15;
465	
466	    // Check X movement
467	    const newX = player.x + dx;
468	    if (isWalkable(Math.floor(newX + 0.3), Math.floor(player.y + 0.3)) &&
469	        isWalkable(Math.floor(newX + 0.8), Math.floor(player.y + 0.3)) &&
470	        isWalkable(Math.floor(newX + 0.3), Math.floor(player.y + 0.8)) &&
471	        isWalkable(Math.floor(newX + 0.8), Math.floor(player.y + 0.8))) {
472	      player.x = newX;
473	    }
474	
475	    // Check Y movement
476	    const newY = player.y + dy;
477	    if (isWalkable(Math.floor(player.x + 0.3), Math.floor(newY + 0.3)) &&
478	        isWalkable(Math.floor(player.x + 0.8), Math.floor(newY + 0.3)) &&
479	        isWalkable(Math.floor(player.x + 0.3), Math.floor(newY + 0.8)) &&
480	        isWalkable(Math.floor(player.x + 0.8), Math.floor(newY + 0.8))) {
481	      player.y = newY;
482	    }
483	  }
484	
485	  // Update camera to follow player
486	  camX = player.x * TILE - canvas.width / 2 + TILE / 2;
487	  camY = player.y * TILE - canvas.height / 2 + TILE / 2;
488	
489	  // Clamp camera
490	  camX = Math.max(0, Math.min(camX, COLS * TILE - canvas.width));
491	  camY = Math.max(0, Math.min(camY, ROWS * TILE - canvas.height));
492	
493	  // Clear
494	  ctx.clearRect(0, 0, canvasW, canvasH);
495	
496	  // Draw tiles
497	  const startCol = Math.max(0, Math.floor(camX / TILE));
498	  const startRow = Math.max(0, Math.floor(camY / TILE));
499	  const endCol = Math.min(COLS - 1, Math.ceil((camX + canvasW) / TILE));
500	  const endRow = Math.min(ROWS - 1, Math.ceil((camY + canvasH) / TILE));
501	
502	  for (let y = startRow; y <= endRow; y++) {
503	    for (let x = startCol; x <= endCol; x++) {
504	      const tile = officeMap[y][x];
505	      if (tile !== undefined) drawTile(x, y, tile);
506	    }
507	  }
508	
509	  // Draw sports floors on top of tiles
510	  drawSportsFloor();
511	
512	  // Draw agent sprites on their desks
513	  const agentPositions = getAgentPositions();
514	  agentPositions.forEach(({ x, y, agent }) => {
515	    const screenX = x * TILE - camX + 8;
516	    const screenY = y * TILE - camY + 8;
517	    drawAgentSprite(agent, screenX, screenY);
518	  });
519	
520	  // Draw player on top
521	  drawPlayer();
522	
523	  // Draw room labels as floor text
524	  ctx.fillStyle = 'rgba(255,255,255,0.3)';
525	  ctx.font = '4px "Press Start 2P", monospace';
526	
527	  // Check for interaction hint
528	  const tileAtPlayer = getTileAt(Math.floor(player.x + 0.5), Math.floor(player.y + 0.5));
529	  if (tileAtPlayer === 6) {
530	    showTooltip('Press E to interact');
531	  }
532	
533	  requestAnimationFrame(render);
534	}
