const { spawn } = require('child_process');

// Spawn a detached background claude process that survives parent exit
function spawnBackgroundProcess(name, cmd) {
  const env = buildEnvScript();
  const logFile = path.join(__dirname, `logs/${name}-${Date.now()}.log`);
  const logsDir = path.join(__dirname, 'logs');
  if (!fs.existsSync(logsDir)) fs.mkdirSync(logsDir, { recursive: true });

  // Parse cli args from cmd string (handles --flag and "quoted strings")
  const parts = parseCliArgs(cmd);

  const child = spawn(env.CLAUDE_BIN, parts, {
    detached: true,
    stdio: ['ignore', 'pipe', 'pipe'],
    env: { ...process.env, ...env }
  });

  const logStream = fs.createWriteStream(logFile, { flags: 'a' });
  child.stdout.pipe(logStream);
  child.stderr.pipe(logStream);

  child.unref(); // fully detach from parent
  return { pid: child.pid, logFile };
}

function parseCliArgs(input) {
  const args = [];
  let current = '';
  let inQuote = false;

  for (let i = 0; i < input.length; i++) {
    const c = input[i];
    if (c === '"' && !inQuote) {
      inQuote = true;
    } else if (c === '"' && inQuote) {
      inQuote = false;
      args.push(current);
      current = '';
    } else if (c === ' ' && !inQuote) {
      if (current) args.push(current);
      current = '';
    } else {
      current += c;
    }
  }
  if (current) args.push(current);
  return args;
}

