input.new_string:
document.getElementById('wakeAgentsBtn').onclick = async () => {
  try {
    const response = await fetch(`${API_BASE}/api/agents`);
    const data = await response.json();
    const sleepingAgents = (data.agents || []).filter(a => !a.sessionActive);

    if (sleepingAgents.length === 0) {
      showNotification('All agents are awake - no one needs waking!', 3000);
      return;
    }

    let woke = 0;
    const resumeCommands = [];
    for (const agent of sleepingAgents) {
      try {
        const resp = await fetch(`${API_BASE}/api/wake/${agent.teamName}`, { method: 'POST' });
        const result = await resp.json();
        if (!result.canSpawn) {
          resumeCommands.push(`claude -r ${agent.teamName}`);
          woke++;
        } else if (result.agents?.length > 0) {
          woke++;
        }
      } catch (err) {
        console.error(`Failed to resume ${agent.name}:`, err);
      }
    }

    if (resumeCommands.length > 0) {
      showNotification(
        `<strong>Woke up ${woke} agent(s)!</strong><br>Open a terminal and run:<br><code>${resumeCommands.join('<br>')}</code>`,
        10000
      );
    } else {
      showNotification(`<strong>Woke up ${woke} agent(s)!</strong><br>They will appear on the map shortly.`, 5000);
    }
    setTimeout(refreshData, 3000);
  } catch (err) {
    console.error('Wake agents up error:', err);
    showNotification('Failed to wake agents.', 3000);
  }
};

