  const desks = [
    { x: 5, y: 3 }, { x: 8, y: 3 }, { x: 11, y: 3 }, { x: 14, y: 3 },
    { x: 5, y: 7 }, { x: 8, y: 7 }, { x: 11, y: 7 }, { x: 14, y: 7 }
  ];

  agents.forEach((agent, i) => {
    if (i < desks.length) {
      positions.push({ ...desks[i], agent });
    }
  });

  return positions;
}

